function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    let mustEdges: number[][] = [];
    let optionalEdges: number[][] = [];

    for (const [u, v, s, m] of edges) {
        if (m === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    class DSU {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = Array.from({ length: size }, (_, i) => i);
            this.rank = Array.from({ length: size }, () => 0);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false; // Already connected
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    const dsu = new DSU(n);
    for (const [u, v, s] of mustEdges) {
        dsu.union(u, v);
    }

    // Check if must-edges already form a disconnected graph
    let root = dsu.find(0);
    for (let i = 1; i < n; i++) {
        if (dsu.find(i) !== root) {
            return -1; // Not connected, cannot form a spanning tree
        }
    }

    // Sort optional edges by strength (we want to choose the strongest ones)
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Try to select optional edges to maximize the minimum strength
    // We use a priority queue (max-heap) to keep track of the strongest edges
    // We also use a DSU to check connectivity
    const maxHeap = new MaxHeap((a, b) => b[2] - a[2]);
    for (const [u, v, s] of optionalEdges) {
        maxHeap.push([u, v, s]);
    }

    // Try different possible minimum strengths
    let answer = -1;
    let currentK = k;

    while (maxHeap.size() > 0) {
        const [u, v, s] = maxHeap.pop() as [number, number, number];
        // Try to include this edge with its original strength
        if (dsu.union(u, v)) {
            answer = Math.max(answer, s);
        } else {
            // If the edge is not needed, we can try to upgrade it
            if (currentK > 0) {
                const upgradedStrength = s * 2;
                if (dsu.union(u, v)) {
                    answer = Math.max(answer, upgradedStrength);
                    currentK--;
                }
            }
        }
    }

    return answer;
}

// MaxHeap implementation
class MaxHeap {
    private heap: [number, number, number][]; // [u, v, strength]
    private compare: (a: [number, number, number], b: [number, number, number]) => number;

    constructor(compare: (a: [number, number, number], b: [number, number, number]) => number) {
        this.heap = [];
        this.compare = compare;
    }

    get size(): number {
        return this.heap.length;
    }

    push(value: [number, number, number]): void {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }

    pop(): [number, number, number] | undefined {
        if (this.heap.length === 0) return undefined;
        const temp = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapifyDown(0);
        return temp;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.compare(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let largest = index;

        if (left < this.heap.length && this.compare(this.heap[left], this.heap[largest]) >= 0) {
            largest = left;
        }

        if (right < this.heap.length && this.compare(this.heap[right], this.heap[largest]) >= 0) {
            largest = right;
        }

        if (largest !== index) {
            [this.heap[index], this.heap[largest]] = [this.heap[largest], this.heap[index]];
            this.heapifyDown(largest);
        }
    }
}

